patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..c2b208329c18 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,31 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq (and (add X, -1), -3), 0) --> (icmp ne (and X, 1), 0)
+  // This transformation is valid when the range of X is within [0, 4).
+  // For X in [0, 4): (X - 1) & -3 == 0 iff X & 1 != 0
+  // Note: -3 = ~2, i.e., all bits except bit 1 are set.
+  if (Cmp.getPredicate() == ICmpInst::ICMP_EQ && C.isZero() &&
+      And->hasOneUse()) {
+    Value *X;
+    const APInt *Addend, *Mask;
+    if (match(And, m_And(m_OneUse(m_Add(m_Value(X), m_APInt(Addend))),
+                         m_APInt(Mask)))) {
+      // Check if Addend == -1 and Mask == -3 (which is ~2)
+      unsigned BitWidth = Mask->getBitWidth();
+      if (*Addend == -1 && *Mask == APInt::getAllOnes(BitWidth) - 2) {
+        // Check if range of X is within [0, 4)
+        // For ConstantRange, getUpper() returns the value just past the end
+        ConstantRange Range = computeConstantRange(X, /*ForSigned=*/false);
+        if (Range.getLower().isMinValue() && Range.getUpper().ule(4)) {
+          Value *NewAnd = Builder.CreateAnd(X, ConstantInt::get(X->getType(), 1));
+          return new ICmpInst(ICmpInst::ICMP_NE, NewAnd,
+                              ConstantInt::getNullValue(X->getType()));
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

